mapper.update:
/* com.educare.edu.comn.mapper.LectureRoomMapper.updateByPk */
	update t_lecture_room
	set 
	mod_id = #{modId}
	,mod_dt = #{modDt}
	,room_nm = #{roomNm}
	,place = #{place}
	,memo = #{memo}
	,use_yn = #{useYn}
	where room_seq = #{roomSeq}

mapper.select:
/* com.educare.edu.comn.mapper.LectureRoomMapper.selectByParam */
	SELECT * FROM t_lecture_room
	WHERE 1=1 

	and ROOM_SEQ = #{roomSeq} 


	and USE_YN = #{useYn} 

	order by room_nm

/* com.educare.edu.comn.mapper.LectureRoomMapper.selectPageList */
	SELECT * FROM t_lecture_room
	WHERE 1=1 

	order by room_seq asc
	limit #{firstIndex} , #{rowCnt}
